import React, { useEffect, useState } from "react";
import Navbar from "./Navbar";
import "./Home.css";

function Home() {
  const [username, setUsername] = useState("");
  const [products, setProducts] = useState([]);
  const [featuredProducts, setFeaturedProducts] = useState([]);
  const [searchQuery, setSearchQuery] = useState("");
  const [selectedCategory, setSelectedCategory] = useState("all");
  const [email, setEmail] = useState("");
  const [newsletterMessage, setNewsletterMessage] = useState("");

  const categories = [
    { id: "all", name: "All Products", description: "Everything you need" },
    { id: "electronics", name: "Electronics", description: "Smart gadgets" },
    { id: "fashion", name: "Fashion", description: "Trending styles" },
    { id: "home", name: "Home", description: "Decor & essentials" },
    { id: "fitness", name: "Fitness", description: "Sports gear" }
  ];

  const testimonials = [
    { name: "Aisha K.", text: "Excellent products and very fast delivery. Highly recommended!" },
    { name: "Rahul S.", text: "The website looks great and the product search works perfectly." },
    { name: "Neha P.", text: "Best shopping experience I have had in a long time." }
  ];

  const inferCategory = (product) => {
    const name = product.name?.toLowerCase() || "";
    if (name.includes("phone") || name.includes("laptop") || name.includes("camera")) return "electronics";
    if (name.includes("shirt") || name.includes("jeans") || name.includes("jacket")) return "fashion";
    if (name.includes("sofa") || name.includes("lamp") || name.includes("table")) return "home";
    if (name.includes("ball") || name.includes("bike") || name.includes("fitness")) return "fitness";
    return "all";
  };

  useEffect(() => {
    const storedUser = localStorage.getItem("username");
    if (storedUser) {
      setUsername(storedUser);
    } else {
      window.location.href = "/";
    }

    fetch("/api/products")
      .then((res) => res.json())
      .then((data) => {
        const enriched = data.map((product) => ({
          ...product,
          category: product.category || inferCategory(product)
        }));
        setProducts(enriched);
        setFeaturedProducts(enriched.slice(0, 6));
      })
      .catch((err) => console.error("Error fetching products:", err));
  }, []);

  const filteredProducts = products.filter((product) => {
    const matchesCategory = selectedCategory === "all" || product.category === selectedCategory;
    const matchesSearch = product.name.toLowerCase().includes(searchQuery.toLowerCase());
    return matchesCategory && matchesSearch;
  });

  const goToProducts = () => {
    window.location.href = "/products";
  };

  const selectCategory = (id) => {
    setSelectedCategory(id);
    setSearchQuery("");
  };

  const handleNewsletterSignup = () => {
    if (!email) {
      setNewsletterMessage("Please enter a valid email.");
      return;
    }
    setNewsletterMessage("Thank you for subscribing! 🎉");
    setEmail("");
    setTimeout(() => setNewsletterMessage(""), 3000);
  };

  return (
    <div className="marketplace-home">
      <Navbar />

      <section className="market-hero">
        <div className="hero-copy">
          <span className="hero-tag">Modern Marketplace</span>
          <h1>Discover the Best Products from Trusted Sellers</h1>
          <p>
            Browse curated collections, shop trending items, and enjoy fast delivery.
            Everything for your home, lifestyle, and work in one place.
          </p>
          <div className="hero-actions">
            <button className="btn btn-primary" onClick={goToProducts}>
              Start Shopping
            </button>
            <button className="btn btn-secondary" onClick={() => selectCategory("all")}>Explore Categories</button>
          </div>
          <div className="hero-metrics">
            <div>
              <strong>15K+</strong>
              <span>Products</span>
            </div>
            <div>
              <strong>8K+</strong>
              <span>Happy Customers</span>
            </div>
            <div>
              <strong>24/7</strong>
              <span>Support</span>
            </div>
          </div>
        </div>
        <div className="hero-image">
          <img src="https://images.pexels.com/photos/7156886/pexels-photo-7156886.jpeg?auto=compress&cs=tinysrgb&w=900" alt="Marketplace hero" />
        </div>
      </section>

      <section className="category-section">
        <div className="section-header">
          <p className="section-label">Shop by category</p>
          <h2>Find your favorites in every category</h2>
        </div>
        <div className="category-grid">
          {categories.map((cat) => (
            <button
              key={cat.id}
              className={`category-card ${selectedCategory === cat.id ? "active" : ""}`}
              onClick={() => selectCategory(cat.id)}
            >
              <h3>{cat.name}</h3>
              <p>{cat.description}</p>
            </button>
          ))}
        </div>
      </section>

      <section className="search-section">
        <div className="search-panel">
          <input
            type="text"
            placeholder="Search trending items, brands, or categories"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
          />
          <button onClick={goToProducts}>Search</button>
        </div>
      </section>

      <section className="featured-products-section">
        <div className="section-header">
          <p className="section-label">Featured Collection</p>
          <h2>Trending products customers love</h2>
        </div>
        <div className="featured-grid">
          {featuredProducts.map((product) => (
            <div key={product.id} className="product-card modern-card">
              <img src={product.image || "https://via.placeholder.com/300"} alt={product.name} />
              <div className="product-card-body">
                <p className="product-category">{product.category || "Other"}</p>
                <h3>{product.name}</h3>
                <p className="product-price">₹{product.price}</p>
                <button className="btn btn-outline" onClick={goToProducts}>View Product</button>
              </div>
            </div>
          ))}
        </div>
      </section>

      <section className="brands-section">
        <div className="section-header inline">
          <p className="section-label">Trusted partners</p>
          <h2>Brands powering your shopping experience</h2>
        </div>
        <div className="brands-grid">
          <span>Flowmart</span>
          <span>UrbanX</span>
          <span>NextTrend</span>
          <span>PureHome</span>
          <span>ActiveFit</span>
        </div>
      </section>

      <section className="testimonials-section">
        <div className="section-header">
          <p className="section-label">Customer stories</p>
          <h2>What shoppers say about us</h2>
        </div>
        <div className="testimonials-grid">
          {testimonials.map((testimonial, index) => (
            <div key={index} className="testimonial-card modern-card">
              <p className="testimonial-text">“{testimonial.text}”</p>
              <p className="testimonial-author">— {testimonial.name}</p>
            </div>
          ))}
        </div>
      </section>

      <section className="newsletter-section modern-card">
        <div className="newsletter-copy">
          <h2>Stay updated with our latest arrivals</h2>
          <p>Subscribe for exclusive offers and new product launches.</p>
        </div>
        <div className="newsletter-form">
          <input
            type="email"
            placeholder="Your email address"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
          />
          <button className="btn btn-primary" onClick={handleNewsletterSignup}>Subscribe</button>
        </div>
        {newsletterMessage && <p className="newsletter-message">{newsletterMessage}</p>}
      </section>
    </div>
  );
}

export default Home;
